create or replace function private.business_team_permission_catalog() returns text[] language sql immutable set search_path=pg_catalog as $$ select array[ 'team.view','team.manage','notifications.view','notifications.manage','accounting.view','accounting.manage','banking.view','banking.manage','tax.view','tax.manage','budget.view','budget.manage','budget.approve','documents.view','documents.manage','branches.view','branches.manage','approvals.view','approvals.request','approvals.decide','approvals.manage','payroll.view','payroll.manage','payroll.process','payroll.pay','assets.view','assets.manage','assets.depreciate','assets.dispose','contacts.view','contacts.manage','sales.view','sales.manage','sales.collect','sales.return','purchases.view','purchases.manage','purchases.pay','purchases.return','inventory.view','inventory.manage','inventory.transfer','inventory.adjust','crm.view','crm.manage','reports.view','shop.view','shop.sell','shop.purchase','shop.expense' ]::text[];$$;

create or replace function private.can_view_business_assets(p_business_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$ select (select auth.uid()) is not null and exists(select 1 from public.business_members membership join public.businesses business on business.id=membership.business_id where membership.business_id=p_business_id and membership.user_id=(select auth.uid()) and membership.status='active' and business.status='active' and (membership.role in ('owner','admin','accountant','manager') or '*'=any(membership.permissions) or 'assets.view'=any(membership.permissions) or 'assets.manage'=any(membership.permissions) or 'assets.depreciate'=any(membership.permissions) or 'assets.dispose'=any(membership.permissions)));$$;

create or replace function private.can_manage_business_assets(p_business_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$ select (select auth.uid()) is not null and exists(select 1 from public.business_members membership join public.businesses business on business.id=membership.business_id where membership.business_id=p_business_id and membership.user_id=(select auth.uid()) and membership.status='active' and business.status='active' and (membership.role in ('owner','admin','accountant') or '*'=any(membership.permissions) or 'assets.manage'=any(membership.permissions)));$$;

create or replace function private.can_depreciate_business_assets(p_business_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$ select (select auth.uid()) is not null and exists(select 1 from public.business_members membership join public.businesses business on business.id=membership.business_id where membership.business_id=p_business_id and membership.user_id=(select auth.uid()) and membership.status='active' and business.status='active' and (membership.role in ('owner','admin','accountant') or '*'=any(membership.permissions) or 'assets.depreciate'=any(membership.permissions) or 'assets.manage'=any(membership.permissions)));$$;

create or replace function private.can_dispose_business_assets(p_business_id uuid) returns boolean language sql stable security definer set search_path=pg_catalog,public as $$ select (select auth.uid()) is not null and exists(select 1 from public.business_members membership join public.businesses business on business.id=membership.business_id where membership.business_id=p_business_id and membership.user_id=(select auth.uid()) and membership.status='active' and business.status='active' and (membership.role in ('owner','admin') or '*'=any(membership.permissions) or 'assets.dispose'=any(membership.permissions)));$$;

create or replace function private.guard_business_asset_write() returns trigger language plpgsql set search_path=pg_catalog as $$ declare expected_action text; begin expected_action:=case tg_table_name when 'business_asset_settings' then 'settings_write' when 'business_asset_categories' then 'category_write' when 'business_fixed_assets' then 'asset_write' when 'business_asset_depreciation_runs' then 'run_write' when 'business_asset_depreciation_lines' then 'line_write' when 'business_asset_audit_log' then 'audit_write' else 'blocked' end; if coalesce(current_setting('app.business_asset_action',true),'')<>expected_action then raise exception 'Direct fixed asset writes are not allowed.' using errcode='42501'; end if; if tg_op='DELETE' then return old;end if; return new; end;$$;

drop trigger if exists business_asset_settings_guard on public.business_asset_settings;
create trigger business_asset_settings_guard before insert or update or delete on public.business_asset_settings for each row execute function private.guard_business_asset_write();

drop trigger if exists business_asset_categories_guard on public.business_asset_categories;
create trigger business_asset_categories_guard before insert or update or delete on public.business_asset_categories for each row execute function private.guard_business_asset_write();

drop trigger if exists business_fixed_assets_guard on public.business_fixed_assets;
create trigger business_fixed_assets_guard before insert or update or delete on public.business_fixed_assets for each row execute function private.guard_business_asset_write();

drop trigger if exists business_asset_depreciation_runs_guard on public.business_asset_depreciation_runs;
create trigger business_asset_depreciation_runs_guard before insert or update or delete on public.business_asset_depreciation_runs for each row execute function private.guard_business_asset_write();

drop trigger if exists business_asset_depreciation_lines_guard on public.business_asset_depreciation_lines;
create trigger business_asset_depreciation_lines_guard before insert or update or delete on public.business_asset_depreciation_lines for each row execute function private.guard_business_asset_write();

drop trigger if exists business_asset_audit_guard on public.business_asset_audit_log;
create trigger business_asset_audit_guard before insert or update or delete on public.business_asset_audit_log for each row execute function private.guard_business_asset_write();

drop trigger if exists business_asset_settings_updated_at on public.business_asset_settings;
create trigger business_asset_settings_updated_at before update on public.business_asset_settings for each row execute function private.set_business_workspace_updated_at();

drop trigger if exists business_asset_categories_updated_at on public.business_asset_categories;
create trigger business_asset_categories_updated_at before update on public.business_asset_categories for each row execute function private.set_business_workspace_updated_at();

drop trigger if exists business_fixed_assets_updated_at on public.business_fixed_assets;
create trigger business_fixed_assets_updated_at before update on public.business_fixed_assets for each row execute function private.set_business_workspace_updated_at();

drop trigger if exists business_asset_depreciation_runs_updated_at on public.business_asset_depreciation_runs;
create trigger business_asset_depreciation_runs_updated_at before update on public.business_asset_depreciation_runs for each row execute function private.set_business_workspace_updated_at();

create or replace function private.write_business_asset_audit(p_business_id uuid,p_asset_id uuid,p_run_id uuid,p_action text,p_metadata jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=pg_catalog,public as $$ begin perform set_config('app.business_asset_action','audit_write',true); insert into public.business_asset_audit_log(business_id,asset_id,depreciation_run_id,actor_user_id,action,metadata) values(p_business_id,p_asset_id,p_run_id,auth.uid(),p_action,coalesce(p_metadata,'{}'::jsonb)); end;$$;

create or replace function private.validate_business_asset_branch(p_business_id uuid,p_branch_id uuid,p_user_id uuid,p_require_access boolean default true) returns void language plpgsql stable security definer set search_path=pg_catalog,public,private as $$ begin if p_branch_id is null then return;end if; if not exists(select 1 from public.business_branches branch where branch.business_id=p_business_id and branch.id=p_branch_id and branch.status='active') then raise exception 'Asset branch is unavailable.' using errcode='22023'; end if; if p_require_access and not private.has_business_branch_access(p_business_id,p_branch_id,p_user_id) then raise exception 'You cannot access fixed assets for this branch.' using errcode='42501'; end if; end;$$;

create or replace function private.ensure_business_asset_foundation(p_business_id uuid,p_actor_id uuid) returns void language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare v_base_currency text; asset_account_id uuid; accumulated_account_id uuid; expense_account_id uuid; gain_account_id uuid; loss_account_id uuid; begin select business.base_currency into v_base_currency from public.businesses business where business.id=p_business_id and business.status='active'; if v_base_currency is null then raise exception 'Active business not found.' using errcode='P0002';end if; select id into asset_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='fixed_assets'; if asset_account_id is null then insert into public.business_chart_of_accounts(business_id,code,name,account_type,account_subtype,normal_balance,system_key,allow_manual_posting,created_by) values(p_business_id,'1500-FA','Property, plant and equipment','asset','fixed_asset','debit','fixed_assets',false,p_actor_id) on conflict(business_id,code) do nothing; select id into asset_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='fixed_assets'; end if; if asset_account_id is not null then update public.business_chart_of_accounts set name='Property, plant and equipment',account_type='asset',account_subtype='fixed_asset',normal_balance='debit',allow_manual_posting=false,updated_at=now() where business_id=p_business_id and id=asset_account_id; end if; select id into accumulated_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='accumulated_depreciation'; if accumulated_account_id is null then insert into public.business_chart_of_accounts(business_id,code,name,account_type,account_subtype,normal_balance,system_key,allow_manual_posting,created_by) values(p_business_id,'1590-FA','Accumulated depreciation','asset','contra_asset','credit','accumulated_depreciation',false,p_actor_id) on conflict(business_id,code) do nothing; select id into accumulated_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='accumulated_depreciation'; end if; select id into expense_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='depreciation_expense'; if expense_account_id is null then insert into public.business_chart_of_accounts(business_id,code,name,account_type,account_subtype,normal_balance,system_key,allow_manual_posting,created_by) values(p_business_id,'6600-FA','Depreciation expense','expense','depreciation','debit','depreciation_expense',false,p_actor_id) on conflict(business_id,code) do nothing; select id into expense_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='depreciation_expense'; end if; if expense_account_id is not null then update public.business_chart_of_accounts set name='Depreciation expense',account_type='expense',account_subtype='depreciation',normal_balance='debit',allow_manual_posting=false,updated_at=now() where business_id=p_business_id and id=expense_account_id; end if; select id into gain_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='gain_on_asset_disposal'; if gain_account_id is null then insert into public.business_chart_of_accounts(business_id,code,name,account_type,account_subtype,normal_balance,system_key,allow_manual_posting,created_by) values(p_business_id,'4910-FA','Gain on disposal of assets','revenue','asset_disposal','credit','gain_on_asset_disposal',false,p_actor_id) on conflict(business_id,code) do nothing; select id into gain_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='gain_on_asset_disposal'; end if; select id into loss_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='loss_on_asset_disposal'; if loss_account_id is null then insert into public.business_chart_of_accounts(business_id,code,name,account_type,account_subtype,normal_balance,system_key,allow_manual_posting,created_by) values(p_business_id,'6910-FA','Loss on disposal of assets','expense','asset_disposal','debit','loss_on_asset_disposal',false,p_actor_id) on conflict(business_id,code) do nothing; select id into loss_account_id from public.business_chart_of_accounts where business_id=p_business_id and system_key='loss_on_asset_disposal'; end if; if asset_account_id is null or accumulated_account_id is null or expense_account_id is null or gain_account_id is null or loss_account_id is null then raise exception 'Fixed asset accounting foundation could not be initialized without changing an existing chart code.' using errcode='23503'; end if; perform set_config('app.business_asset_action','settings_write',true); insert into public.business_asset_settings(business_id,gain_on_disposal_account_id,loss_on_disposal_account_id,updated_by) values(p_business_id,gain_account_id,loss_account_id,p_actor_id) on conflict(business_id) do update set gain_on_disposal_account_id=excluded.gain_on_disposal_account_id,loss_on_disposal_account_id=excluded.loss_on_disposal_account_id,updated_by=excluded.updated_by; perform set_config('app.business_asset_action','category_write',true); insert into public.business_asset_categories(business_id,code,name,description,asset_account_id,accumulated_depreciation_account_id,depreciation_expense_account_id,default_useful_life_months,default_residual_rate,created_by,updated_by) values(p_business_id,'GENERAL','General fixed assets','Default fixed asset category.',asset_account_id,accumulated_account_id,expense_account_id,60,0,p_actor_id,p_actor_id) on conflict(business_id,code) do nothing; end;$$;

create or replace function private.initialize_business_assets_on_owner() returns trigger language plpgsql security definer set search_path=pg_catalog,public,private as $$ begin if new.role='owner' and new.status='active' then perform private.ensure_business_asset_foundation(new.business_id,new.user_id); end if; return new; end;$$;

drop trigger if exists business_members_initialize_assets on public.business_members;
create trigger business_members_initialize_assets after insert or update of role,status on public.business_members for each row execute function private.initialize_business_assets_on_owner();

do $$declare rec record;begin for rec in select id,owner_user_id from public.businesses where status='active' loop perform private.ensure_business_asset_foundation(rec.id,rec.owner_user_id); end loop; end$$;
